import React from 'react';
import './projets.css'; // Assurez-vous d'avoir un fichier Grid.css pour les styles

function Pjt() {
  return (
    <div class="angry-grid">
      <div id="item-0">
        <p>
          Voici mes projets réalisés lors de ma formation avec Openclassroom
        </p>
      </div>
      <div id="item-1">&nbsp;</div>
      <div id="item-2">&nbsp;</div>
      <div id="item-3">&nbsp;</div>
      <div id="item-4">&nbsp;</div>
    </div>
  );
}

export default Pjt;
